class Solution:
    def maxDistance(self, grid):
        n = len(grid)
        lands = [(i, j) for i in range(n) for j in range(n) if grid[i][j] == 1]
        waters = [(i, j) for i in range(n) for j in range(n) if grid[i][j] == 0]
        if not lands or not waters:
            return -1
        best = -1
        for (wi, wj) in waters:
            d = min(abs(wi - li) + abs(wj - lj) for (li, lj) in lands)
            best = max(best, d)
        return best

