class Solution:
    def maxDistance(self, grid):
        from collections import deque
        n = len(grid)
        q = deque()
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 1:
                    q.append((i, j))
        if len(q) == 0 or len(q) == n * n:
            return -1
        dist = -1
        seen = [[grid[i][j] == 1 for j in range(n)] for i in range(n)]
        while q:
            dist += 1
            for _ in range(len(q)):
                i, j = q.popleft()
                for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    ni, nj = i + di, j + dj
                    if 0 <= ni < n and 0 <= nj < n and not seen[ni][nj]:
                        seen[ni][nj] = True
                        q.append((ni, nj))
        return dist

