var maxDistance = function(grid) {
    const n = grid.length;
    let q = [];
    const seen = Array.from({ length: n }, () => new Array(n).fill(false));
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) { q.push([i, j]); seen[i][j] = true; }
        }
    }
    if (q.length === 0 || q.length === n * n) return -1;
    let dist = -1;
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    while (q.length) {
        dist++;
        const nq = [];
        for (const [i, j] of q) {
            for (const [di, dj] of dirs) {
                const ni = i + di, nj = j + dj;
                if (ni >= 0 && ni < n && nj >= 0 && nj < n && !seen[ni][nj]) {
                    seen[ni][nj] = true;
                    nq.push([ni, nj]);
                }
            }
        }
        q = nq;
    }
    return dist;
};
